query:
-- Delete quiz questions for these lessons  
DELETE FROM quiz_questions WHERE lessonId IN (
  SELECT id FROM lessons WHERE (courseId = 4 AND lessonOrder IN (8, 9)) OR (courseId = 6 AND lessonOrder = 9)
);

-- Delete the lessons
DELETE FROM lessons WHERE (courseId = 4 AND lessonOrder IN (8, 9)) OR (courseId = 6 AND lessonOrder = 9);

-- Update course totals
UPDATE courses SET totalLessons = 7 WHERE id = 4;
UPDATE courses SET totalLessons = 8 WHERE id = 6;

